import tiktoken
from dataclasses import dataclass, field

@dataclass
class AgentContextBudget:
    model: str = "gpt-4o"
    context_window: int = 128_000
    max_completion_tokens: int = 4_096
    system_prompt_tokens: int = 0   # pre-measured at startup
    history_limit: int = 60_000     # token budget for rolling history

    messages: list[dict] = field(default_factory=list)

    def _token_count(self, text: str) -> int:
        enc = tiktoken.encoding_for_model(self.model)
        return len(enc.encode(text))

    def _history_tokens(self) -> int:
        return sum(self._token_count(m["content"]) + 4 for m in self.messages)

    def _total_input_tokens(self) -> int:
        return self.system_prompt_tokens + self._history_tokens()

    def is_near_limit(self, threshold: float = 0.88) -> bool:
        budget = self.context_window - self.max_completion_tokens
        return self._total_input_tokens() / budget >= threshold

    def drop_oldest_tool_exchange(self) -> bool:
        """Remove the oldest tool result message from history."""
        for i, msg in enumerate(self.messages):
            if msg.get("role") == "tool":
                # Also drop the preceding assistant tool_call message if present
                if i > 0 and self.messages[i - 1].get("role") == "assistant":
                    del self.messages[i - 1 : i + 1]
                else:
                    del self.messages[i]
                return True
        return False

    def enforce_budget(self) -> int:
        """Drop oldest tool exchanges until under the threshold. Returns count."""
        drops = 0
        while self.is_near_limit() and self.drop_oldest_tool_exchange():
            drops += 1
        return drops

# Simulate 20 agent turns with growing tool results
budget = AgentContextBudget(system_prompt_tokens=800)
for turn in range(20):
    # Tool results grow larger over time (simulating accumulation)
    tool_result_text = f"Result for step {turn}: " + "analysis data " * (40 + turn * 8)
    budget.messages.append({"role": "tool", "content": tool_result_text})
    dropped = budget.enforce_budget()
    used = budget._total_input_tokens()
    pct = used / (budget.context_window - budget.max_completion_tokens) * 100
    print(f"Turn {turn:02d}: {used:,} tokens ({pct:.0f}%), {dropped} exchanges dropped")
